**Implement a debounce function in JavaScript to limit the rate at which a function can fire.**

```javascript
function debounce(func, delay) {
    let debounceTimer;
    return function(...args) {
        const context = this;
        clearTimeout(debounceTimer);
        debounceTimer = setTimeout(() => func.apply(context, args), delay);
    };
}

// Example usage:
const handleResize = debounce(() => {
    console.log('Resized!');
}, 300);

window.addEventListener('resize', handleResize);
```

In this example, the `handleResize` function will only execute 300 milliseconds after the last resize event, preventing it from firing too frequently.
